class Solution(object):
    def pathExistenceQueries(self, n, nums, maxDiff, queries):
        # Since nums is sorted, connected components are contiguous ranges.
        # Two adjacent nodes i and i+1 are in the same component iff nums[i+1]-nums[i] <= maxDiff.
        # Assign component IDs by scanning left to right.
        comp = [0] * n
        for i in range(1, n):
            if nums[i] - nums[i - 1] <= maxDiff:
                comp[i] = comp[i - 1]
            else:
                comp[i] = comp[i - 1] + 1

        return [comp[u] == comp[v] for u, v in queries]
